import React, { useState } from 'react';
import axios from 'axios';
import SubmitionBar from "../SubmitionBar/SubmitionBar";
import Button from '../Button/Button.jsx'
// import "./Register.css";

const API = axios.create({
  baseURL: 'http://localhost:3001'
});

const Register = ({ }) => {
    const [inputData, setInputData] = useState("");
    const [newUser, setNewUser] = useState({
        nome: "",
        email: "",
        senha: ""
    });

    const handleSubmition = (fieldName) => (value) => {
        setNewUser(prev => ({
            ...prev,
            [fieldName]: value
        }));
        console.log(`${fieldName} atualizado:`, value);
    };



    const handleInputChange = (newUser) => {
        setInputData(newUser.target.value);
    };

    

    return (
        <div className = "bg-home">
                    <div className = "container-registro" >
                        <header>Registro</header>
                        <SubmitionBar handleAddition={handleSubmition("nome")} > Digite seu nome. </SubmitionBar>
                        <SubmitionBar handleAddition={handleSubmition("email")} > Digite seu email. </SubmitionBar>
                        <SubmitionBar handleAddition={handleSubmition("senha")} > Digite sua senha. </SubmitionBar>
                        <div style = "width: 20%" > <Button >Submeter</Button> </div>
                    </div>
                </div>
    );
};

export default Register;
